sql:
SELECT test_item_name
FROM test_items
WHERE test_item_id NOT IN (
  SELECT DISTINCT test_item_id
  FROM test_results
);

SELECT test_condition_name, temperature
FROM test_conditions
WHERE test_condition_id = 1;

SELECT COUNT(test_item_id) AS number_of_test_items
FROM test_item_components
WHERE component_id = 1;

SELECT COUNT(*) AS pending_schedules
FROM test_schedules
WHERE test_condition_id = 1 AND status = 'pending';

SELECT schedule_date
FROM test_schedules
WHERE status = 'pending';

SELECT test_result_id
FROM test_results
ORDER BY test_result_id;

SELECT test_item_name
FROM test_items
ORDER BY test_item_name;

SELECT COUNT(*) AS condition_count
FROM test_conditions
WHERE temperature = 150.0;

SELECT test_item_name
FROM test_items
WHERE test_item_id = 1;
